  function injectCardGenres() {
    const genreNames = Object.keys(GENRES).filter(n => n !== 'All');
    document.querySelectorAll('.card').forEach(card => {
      const n = parseInt((card.querySelector('.number') || {}).textContent?.match(/\d+/)?.[0], 10);
      if (isNaN(n)) return;
      const genres = genreNames.filter(name => {
        const set = GENRES[name].nums;
        return set && set.has(n);
      });
      if (genres.length === 0) return;
      const backContent = card.querySelector('.back-content');
      if (!backContent) return;
      const genreDiv = document.createElement('div');
      genreDiv.className = 'back-genre';
      genreDiv.textContent = genres.join(' · ');
      const title = backContent.querySelector('.back-title');
      if (title && title.nextSibling) {
        backContent.insertBefore(genreDiv, title.nextSibling);
      } else {
        const hint = backContent.querySelector('.back-tap-hint');
        if (hint) {
          backContent.insertBefore(genreDiv, hint);
        } else {
          backContent.appendChild(genreDiv);
        }
      }
    });
  }

  function countForGenre(name) {
    const set = GENRES[name].nums;
    if (!set) return getTotalCards();
    let c = 0;
    document.querySelectorAll('.card').forEach(card => {
      const n = parseInt((card.querySelector('.number') || {}).textContent?.match(/\d+/)?.[0], 10);
      if (!isNaN(n) && set.has(n)) c++;
    });
    return c;
  }

  function getNum(card) {
    const el = card.querySelector('.number');
    if (!el) return null;
    const m = el.textContent.match(/\d+/);
    return m ? parseInt(m[0], 10) : null;
  }

  function buildPills() {
    const wrap = document.getElementById('pillsWrap');
    if (!wrap) return;
    Object.entries(GENRES).forEach(([name, g]) => {
      const btn = document.createElement('button');
      btn.className = 'pill' + (name === 'All' ? ' active' : '');
      btn.dataset.genre = name;
      const cnt = countForGenre(name);
      btn.innerHTML = `<span style="font-size:14px">${g.icon}</span>${name}<span class="pill-count">${cnt}</span>`;
      btn.addEventListener('click', () => applyFilter(name));
      wrap.appendChild(btn);
    });
  }

  function applyFilter(name) {
    const set = GENRES[name].nums;
    const cards = document.querySelectorAll('.card');
    let vis = 0;
    cards.forEach(card => {
      const n = getNum(card);
      const show = n !== null && (!set || set.has(n));
      card.style.display = '';
      card.classList.toggle('hidden', !show);
      if (show) vis++;
    });
    updateBadgeNumbers();
    document.querySelectorAll('.pill').forEach(p =>
      p.classList.toggle('active', p.dataset.genre === name));
    const status = document.getElementById('filterStatus');
    if (status) status.innerHTML = `Showing <strong>${vis}</strong> of <strong>${getTotalCards()}</strong> anime`;
    const clr = document.getElementById('clearBtn');
    if (clr) clr.classList.toggle('hidden', name === 'All');
  }

  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    buildPills();
    injectCardGenres();
    var clr = document.getElementById('clearBtn');
    if (clr) clr.addEventListener('click', function() { applyFilter('All'); });
  } else {
    document.addEventListener('DOMContentLoaded', function() {
      buildPills();
      injectCardGenres();
      var clr = document.getElementById('clearBtn');
      if (clr) clr.addEventListener('click', function() { applyFilter('All'); });
    });
  }

    

