function drawPieChart() {
  const GENRES = window.ANIME_GENRES;
  if (!GENRES) return;
  const canvas = document.getElementById('pieChart');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const TOTAL = document.querySelectorAll('.card').length;
  const entries = [];
  Object.entries(GENRES).forEach(([name, g]) => {
    if (name === 'All') return;
    const set = g.nums;
    if (!set) return;
    let count = 0;
    document.querySelectorAll('.card').forEach(card => {
      const n = parseInt((card.querySelector('.number') || {}).textContent?.match(/\d+/)?.[0], 10);
      if (!isNaN(n) && set.has(n)) count++;
    });
    if (count > 0) entries.push({ name, icon: g.icon, count });
  });
  entries.sort((a, b) => b.count - a.count);
  const totalAssign = entries.reduce((s, e) => s + e.count, 0);
  entries.forEach(e => e.pct = (e.count / totalAssign) * 100);

  const colors = ['#FF6B6B','#4ECDC4','#45B7D1','#FFA07A','#98D8C8','#F7DC6F','#BB8FCE','#82E0AA','#F1948A','#85C1E9','#F0B27A','#D2B4DE'];
  const cx = 150, cy = 150, r = 120;

  const slices = [];
  let angleOffset = 0;
  entries.forEach((entry, i) => {
    const sliceAngle = (entry.pct / 100) * Math.PI * 2;
    const color = colors[i % colors.length];
    slices.push({ start: angleOffset, end: angleOffset + sliceAngle, mid: angleOffset + sliceAngle / 2, entry, color });
    angleOffset += sliceAngle;
  });

  let hoverAmount = 0, targetIdx = -1, hoverAnimId = null, entryDone = false;

  function draw(progress, idx, amt) {
    ctx.clearRect(0, 0, 300, 300);
    const drawEnd = progress * angleOffset;
    const a = amt ?? 0;
    const renderOrder = slices.map((_, i) => i).sort((a, b) => (a === idx ? 1 : 0) - (b === idx ? 1 : 0));
    renderOrder.forEach(i => {
      const s = slices[i];
      if (s.start >= drawEnd) return;
      const end = Math.min(s.end, drawEnd);
      const isHover = i === idx;
      const f = isHover ? a : 0;
      const sr = r * (1 + 0.04 * f);
      const off = 12 * f;
      const ox = Math.cos(s.mid) * off;
      const oy = Math.sin(s.mid) * off;
      ctx.beginPath();
      ctx.moveTo(cx + ox, cy + oy);
      ctx.arc(cx + ox, cy + oy, sr, s.start - Math.PI / 2, end - Math.PI / 2);
      ctx.closePath();
      ctx.fillStyle = s.color;
      ctx.fill();
      ctx.strokeStyle = isHover && f > 0.3 ? '#ffd700' : '#0a0e1a';
      ctx.lineWidth = isHover && f > 0.3 ? 3.5 : 2;
      ctx.stroke();
      if (isHover && f > 0.3) {
        ctx.shadowColor = 'rgba(255,215,0,0.6)';
        ctx.shadowBlur = 28 * f;
        ctx.stroke();
        ctx.shadowBlur = 0;
      }
    });
  }

  function animateHover() {
    const t = targetIdx >= 0 ? 1 : 0;
    hoverAmount += (t - hoverAmount) * 0.18;
    if (Math.abs(hoverAmount - t) < 0.001) { hoverAmount = t; if (hoverAnimId) { cancelAnimationFrame(hoverAnimId); hoverAnimId = null; } }
    draw(1, targetIdx >= 0 ? targetIdx : -1, hoverAmount);
    if (Math.abs(hoverAmount - t) > 0.001) hoverAnimId = requestAnimationFrame(animateHover);
  }

  let tooltip = document.getElementById('pieTooltip');
  if (!tooltip) {
    tooltip = document.createElement('div');
    tooltip.id = 'pieTooltip';
    tooltip.style.cssText = 'position:fixed;pointer-events:none;background:rgba(10,14,26,0.92);color:#ffd700;font-family:Exo 2,sans-serif;font-size:13px;font-weight:600;padding:6px 12px;border-radius:8px;border:1px solid rgba(255,215,0,0.3);box-shadow:0 0 12px rgba(255,215,0,0.15);display:none;z-index:999;white-space:nowrap;';
    document.body.appendChild(tooltip);
  }

  const entryDuration = 900;
  const entryStart = performance.now();
  (function anim(now) {
    const t = Math.min((now - entryStart) / entryDuration, 1);
    draw(1 - Math.pow(1 - t, 3), -1, 0);
    if (t < 1) { requestAnimationFrame(anim); } else { entryDone = true; draw(1, -1, 0); }
  })(performance.now());

  function getSliceIdx(mx, my) {
    const rect = canvas.getBoundingClientRect();
    const dx = mx - rect.left - cx, dy = my - rect.top - cy;
    if (Math.sqrt(dx * dx + dy * dy) > r) return -1;
    let angle = Math.atan2(dy, dx) + Math.PI / 2;
    if (angle < 0) angle += Math.PI * 2;
    for (let i = 0; i < slices.length; i++) {
      if (angle >= slices[i].start && angle < slices[i].end) return i;
    }
    return -1;
  }

  function onMove(e) {
    const mx = e.clientX ?? e.touches?.[0]?.clientX;
    const my = e.clientY ?? e.touches?.[0]?.clientY;
    if (mx == null) return;
    const idx = getSliceIdx(mx, my);
    if (idx !== targetIdx) { targetIdx = idx; if (entryDone) animateHover(); }
    if (idx >= 0) {
      tooltip.textContent = `${slices[idx].entry.icon} ${slices[idx].entry.name}: ${entries[idx].pct.toFixed(1)}%`;
      tooltip.style.left = (mx + 14) + 'px';
      tooltip.style.top = (my - 8) + 'px';
      tooltip.style.display = 'block';
      canvas.style.cursor = 'pointer';
    } else { tooltip.style.display = 'none'; canvas.style.cursor = 'default'; }
  }

  function onLeave() { targetIdx = -1; tooltip.style.display = 'none'; canvas.style.cursor = 'default'; if (entryDone) animateHover(); }

  canvas.removeEventListener('mousemove', onMove);
  canvas.removeEventListener('mouseleave', onLeave);
  canvas.removeEventListener('touchmove', onMove);
  canvas.addEventListener('mousemove', onMove);
  canvas.addEventListener('mouseleave', onLeave);
  canvas.addEventListener('touchmove', onMove, { passive: true });

  const legend = document.getElementById('analysisLegend');
  legend.innerHTML = '';
  entries.forEach((entry, i) => {
    const div = document.createElement('div');
    div.className = 'legend-item';
    div.innerHTML = `<span class="legend-color" style="background:${colors[i % colors.length]}"></span><span class="legend-label">${entry.icon} ${entry.name}</span><span class="legend-pct">${entry.pct.toFixed(1)}%</span>`;
    legend.appendChild(div);
  });
}

