function drawStudioPie() {
  if (!window.STUDIO_DATA) return;
  const canvas = document.getElementById('studioChart');
  if (!canvas) return;
  canvas.width = 300; canvas.height = 300;
  const ctx = canvas.getContext('2d');
  const counts = {};
  Object.values(window.STUDIO_DATA).forEach(arr => arr.forEach(s => counts[s] = (counts[s] || 0) + 1));
  let entries = Object.entries(counts).map(([name, count]) => ({ name, count }));
  entries.sort((a, b) => b.count - a.count);
  entries = entries.slice(0, 10);
  const totalAssign = entries.reduce((s, e) => s + e.count, 0);
  entries.forEach(e => e.pct = (e.count / totalAssign) * 100);

  const colors = ['#FF6B6B','#4ECDC4','#45B7D1','#FFA07A','#98D8C8','#F7DC6F','#BB8FCE','#82E0AA','#F1948A','#85C1E9'];
  const cx = 150, cy = 150, r = 120;
  const slices = [];
  let angleOffset = 0;
  entries.forEach((entry, i) => {
    const sliceAngle = (entry.pct / 100) * Math.PI * 2;
    slices.push({ start: angleOffset, end: angleOffset + sliceAngle, mid: angleOffset + sliceAngle / 2, entry, color: colors[i % colors.length] });
    angleOffset += sliceAngle;
  });

  let hoverAmount = 0, targetIdx = -1, hoverAnimId = null, entryDone = false;

  function draw(progress, idx, amt) {
    ctx.clearRect(0, 0, 300, 300);
    const drawEnd = progress * angleOffset;
    const a = amt ?? 0;
    const renderOrder = slices.map((_, i) => i).sort((a, b) => (a === idx ? 1 : 0) - (b === idx ? 1 : 0));
    renderOrder.forEach(i => {
      const s = slices[i];
      if (s.start >= drawEnd) return;
      const end = Math.min(s.end, drawEnd);
      const isHover = i === idx;
      const f = isHover ? a : 0;
      const sr = r * (1 + 0.04 * f);
      const off = 12 * f;
      const ox = Math.cos(s.mid) * off;
      const oy = Math.sin(s.mid) * off;
      ctx.beginPath();
      ctx.moveTo(cx + ox, cy + oy);
      ctx.arc(cx + ox, cy + oy, sr, s.start - Math.PI / 2, end - Math.PI / 2);
      ctx.closePath();
      ctx.fillStyle = s.color;
      ctx.fill();
      ctx.strokeStyle = isHover && f > 0.3 ? '#ffd700' : '#0a0e1a';
      ctx.lineWidth = isHover && f > 0.3 ? 3.5 : 2;
      ctx.stroke();
      if (isHover && f > 0.3) {
        ctx.shadowColor = 'rgba(255,215,0,0.6)';
        ctx.shadowBlur = 28 * f;
        ctx.stroke();
        ctx.shadowBlur = 0;
      }
    });
  }

  function animateHover() {
    const t = targetIdx >= 0 ? 1 : 0;
    hoverAmount += (t - hoverAmount) * 0.18;
    if (Math.abs(hoverAmount - t) < 0.001) { hoverAmount = t; if (hoverAnimId) { cancelAnimationFrame(hoverAnimId); hoverAnimId = null; } }
    draw(1, targetIdx >= 0 ? targetIdx : -1, hoverAmount);
    if (Math.abs(hoverAmount - t) > 0.001) hoverAnimId = requestAnimationFrame(animateHover);
  }

  let tooltip = document.getElementById('pieTooltip');
  if (!tooltip) {
    tooltip = document.createElement('div');
    tooltip.id = 'pieTooltip';
    tooltip.style.cssText = 'position:fixed;pointer-events:none;background:rgba(10,14,26,0.92);color:#ffd700;font-family:Exo 2,sans-serif;font-size:13px;font-weight:600;padding:6px 12px;border-radius:8px;border:1px solid rgba(255,215,0,0.3);box-shadow:0 0 12px rgba(255,215,0,0.15);display:none;z-index:999;white-space:nowrap;';
    document.body.appendChild(tooltip);
  }

  const entryDuration = 900;
  const entryStart = performance.now();
  (function anim(now) {
    const t = Math.min((now - entryStart) / entryDuration, 1);
    draw(1 - Math.pow(1 - t, 3), -1, 0);
    if (t < 1) { requestAnimationFrame(anim); } else { entryDone = true; draw(1, -1, 0); }
  })(performance.now());

  function getSliceIdx(mx, my) {
    const rect = canvas.getBoundingClientRect();
    const dx = mx - rect.left - cx, dy = my - rect.top - cy;
    if (Math.sqrt(dx * dx + dy * dy) > r) return -1;
    let angle = Math.atan2(dy, dx) + Math.PI / 2;
    if (angle < 0) angle += Math.PI * 2;
    for (let i = 0; i < slices.length; i++) {
      if (angle >= slices[i].start && angle < slices[i].end) return i;
    }
    return -1;
  }

  function onMove(e) {
    const mx = e.clientX ?? e.touches?.[0]?.clientX;
    const my = e.clientY ?? e.touches?.[0]?.clientY;
    if (mx == null) return;
    const idx = getSliceIdx(mx, my);
    if (idx !== targetIdx) { targetIdx = idx; if (entryDone) animateHover(); }
    if (idx >= 0) {
      tooltip.textContent = `${slices[idx].entry.pct.toFixed(1)}% - ${slices[idx].entry.name}`;
      tooltip.style.left = (mx + 14) + 'px';
      tooltip.style.top = (my - 8) + 'px';
      tooltip.style.display = 'block';
      canvas.style.cursor = 'pointer';
    } else { tooltip.style.display = 'none'; canvas.style.cursor = 'default'; }
  }

  function onLeave() { targetIdx = -1; tooltip.style.display = 'none'; canvas.style.cursor = 'default'; if (entryDone) animateHover(); }

  canvas.removeEventListener('mousemove', onMove);
  canvas.removeEventListener('mouseleave', onLeave);
  canvas.removeEventListener('touchmove', onMove);
  canvas.addEventListener('mousemove', onMove);
  canvas.addEventListener('mouseleave', onLeave);
  canvas.addEventListener('touchmove', onMove, { passive: true });

  const legend = document.getElementById('studioLegend');
  legend.innerHTML = '';
  entries.forEach((entry, i) => {
    const div = document.createElement('div');
    div.className = 'legend-item';
    div.innerHTML = `<span class="legend-color" style="background:${colors[i % colors.length]}"></span><span class="legend-label">${entry.name}</span><span class="legend-pct">${entry.pct.toFixed(1)}%</span>`;
    legend.appendChild(div);
  });
}

function drawEpisodePie() {
  const canvas = document.getElementById('episodeChart');
  if (!canvas) return;
  canvas.width = 300; canvas.height = 300;
  const ctx = canvas.getContext('2d');

  const buckets = {
    '1–11 eps': 0,
    '12 eps': 0,
    '13 eps': 0,
    '14–23 eps': 0,
    '24–26 eps': 0,
    '27–49 eps': 0,
    '50–99 eps': 0,
    '100+ eps': 0,
    'Movie': 0,
    'N/A': 0,
  };

  document.querySelectorAll('.card').forEach(card => {
    const epText = card.querySelector('.back-episodes')?.textContent || '';
    const seasonText = card.querySelector('.back-season')?.textContent || '';
    const isMovie = /🎬/.test(seasonText) || /Runtime/.test(epText);
    if (isMovie) { buckets['Movie']++; return; }
    const match = epText.match(/[\d,]+/);
    if (!match) { buckets['N/A']++; return; }
    const num = parseInt(match[0].replace(/,/g, ''), 10);
    if (isNaN(num) || epText.includes('Not Agree')) { buckets['N/A']++; return; }
    if (num <= 11) buckets['1–11 eps']++;
    else if (num === 12) buckets['12 eps']++;
    else if (num === 13) buckets['13 eps']++;
    else if (num <= 23) buckets['14–23 eps']++;
    else if (num <= 26) buckets['24–26 eps']++;
    else if (num <= 49) buckets['27–49 eps']++;
    else if (num <= 99) buckets['50–99 eps']++;
    else buckets['100+ eps']++;
  });

  const entries = Object.entries(buckets).filter(([, v]) => v > 0).map(([name, count]) => ({ name, count }));
  const total = entries.reduce((s, e) => s + e.count, 0);
  if (total === 0) { ctx.fillStyle = '#b0d4f0'; ctx.font = '14px Exo 2'; ctx.textAlign = 'center'; ctx.fillText('No data', 150, 150); return; }
  entries.forEach(e => e.pct = (e.count / total) * 100);

  const colors = ['#FF6B6B','#4ECDC4','#45B7D1','#FFA07A','#98D8C8','#F7DC6F','#BB8FCE','#82E0AA','#F1948A','#85C1E9'];
  const cx = 150, cy = 150, r = 120;

  const slices = [];
  let angleOffset = 0;
  entries.forEach((entry, i) => {
    const sliceAngle = (entry.pct / 100) * Math.PI * 2;
    const color = colors[i % colors.length];
    slices.push({ start: angleOffset, end: angleOffset + sliceAngle, mid: angleOffset + sliceAngle / 2, entry, color });
    angleOffset += sliceAngle;
  });

  let hoverAmount = 0, targetIdx = -1, hoverAnimId = null, entryDone = false;

  function draw(progress, idx, amt) {
    ctx.clearRect(0, 0, 300, 300);
    const drawEnd = progress * angleOffset;
    const a = amt ?? 0;
    slices.forEach((sl, i) => {
      if (sl.start >= drawEnd) return;
      const end = Math.min(sl.end, drawEnd);
      const isHover = i === idx;
      const f = isHover ? a : 0;
      const sr = r * (1 + 0.04 * f);
      const off = 12 * f;
      const ox = Math.cos(sl.mid) * off;
      const oy = Math.sin(sl.mid) * off;
      ctx.beginPath();
      ctx.moveTo(cx + ox, cy + oy);
      ctx.arc(cx + ox, cy + oy, sr, sl.start - Math.PI / 2, end - Math.PI / 2);
      ctx.closePath();
      ctx.fillStyle = sl.color;
      ctx.fill();
      ctx.strokeStyle = isHover && f > 0.3 ? '#ffd700' : '#0a0e1a';
      ctx.lineWidth = isHover && f > 0.3 ? 3.5 : 2;
      ctx.stroke();
      if (isHover && f > 0.3) {
        ctx.shadowColor = 'rgba(255,215,0,0.6)';
        ctx.shadowBlur = 28 * f;
        ctx.stroke();
        ctx.shadowBlur = 0;
      }
    });
  }

  function animateEntry() {
    const dur = 900, start = performance.now();
    function step(now) {
      const t = Math.min((now - start) / dur, 1);
      const ease = 1 - Math.pow(1 - t, 3);
      draw(ease, -1, 0);
      if (t < 1) requestAnimationFrame(step);
      else { entryDone = true; buildLegend(); }
    }
    requestAnimationFrame(step);
  }

  function buildLegend() {
    const legend = document.getElementById('episodeLegend');
    if (!legend) return;
    legend.innerHTML = '';
    entries.forEach((entry, i) => {
      const div = document.createElement('div');
      div.className = 'legend-item';
      div.innerHTML = `<span class="legend-color" style="background:${colors[i % colors.length]}"></span><span class="legend-label">${entry.name}</span><span class="legend-pct">${entry.pct.toFixed(1)}%</span>`;
      legend.appendChild(div);
    });
  }

  function animateHover() {
    const t = targetIdx >= 0 ? 1 : 0;
    hoverAmount += (t - hoverAmount) * 0.18;
    if (Math.abs(hoverAmount - t) < 0.001) { hoverAmount = t; if (hoverAnimId) { cancelAnimationFrame(hoverAnimId); hoverAnimId = null; } }
    draw(1, targetIdx >= 0 ? targetIdx : -1, hoverAmount);
    if (Math.abs(hoverAmount - t) > 0.001) hoverAnimId = requestAnimationFrame(animateHover);
  }

  let tooltip = document.getElementById('pieTooltip');
  if (!tooltip) {
    tooltip = document.createElement('div');
    tooltip.id = 'pieTooltip';
    tooltip.style.cssText = 'position:fixed;pointer-events:none;background:rgba(10,14,26,0.92);color:#ffd700;font-family:Exo 2,sans-serif;font-size:13px;font-weight:600;padding:6px 12px;border-radius:8px;border:1px solid rgba(255,215,0,0.3);box-shadow:0 0 12px rgba(255,215,0,0.15);display:none;z-index:999;white-space:nowrap;';
    document.body.appendChild(tooltip);
  }

  function getSliceIdx(mx, my) {
    const rect = canvas.getBoundingClientRect();
    const dx = mx - rect.left - cx, dy = my - rect.top - cy;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist > r || dist < 20) return -1;
    let angle = Math.atan2(dy, dx) + Math.PI / 2;
    if (angle < 0) angle += Math.PI * 2;
    for (let i = 0; i < slices.length; i++) {
      if (angle >= slices[i].start && angle < slices[i].end) return i;
    }
    return -1;
  }

  function onMove(e) {
    const mx = e.clientX ?? e.touches?.[0]?.clientX;
    const my = e.clientY ?? e.touches?.[0]?.clientY;
    if (mx == null) return;
    const idx = getSliceIdx(mx, my);
    if (idx !== targetIdx) { targetIdx = idx; if (entryDone) animateHover(); }
    if (idx >= 0) {
      tooltip.textContent = `${entries[idx].name}: ${entries[idx].pct.toFixed(1)}%`;
      tooltip.style.left = (mx + 14) + 'px';
      tooltip.style.top = (my - 8) + 'px';
      tooltip.style.display = 'block';
      canvas.style.cursor = 'pointer';
    } else { tooltip.style.display = 'none'; canvas.style.cursor = 'default'; }
  }

  function onLeave() { targetIdx = -1; tooltip.style.display = 'none'; canvas.style.cursor = 'default'; if (entryDone) animateHover(); }

  canvas.removeEventListener('mousemove', onMove);
  canvas.removeEventListener('mouseleave', onLeave);
  canvas.removeEventListener('touchmove', onMove);
  canvas.addEventListener('mousemove', onMove);
  canvas.addEventListener('mouseleave', onLeave);
  canvas.addEventListener('touchmove', onMove, { passive: true });

  animateEntry();
}

function drawRatingChart() {
  if (!window.RATING_DATA || !window.OTT_DATA) return;
  const canvas = document.getElementById('ratingChart');
  if (!canvas) return;
  canvas.width = 600; canvas.height = 360;
  const ctx = canvas.getContext('2d');
  const W = 600, H = 360, pad = { top: 16, bottom: 16, left: 160, right: 50 };

  // Get titles from DOM cards
  const numToTitle = {};
  document.querySelectorAll('.card').forEach(card => {
    const numEl = card.querySelector('.number');
    const titleEl = card.querySelector('.title');
    if (numEl && titleEl) {
      const n = parseInt(numEl.textContent.replace(/\D/g, ''), 10);
      if (!isNaN(n)) numToTitle[n] = titleEl.textContent.trim();
    }
  });

  // Get anime on Crunchyroll with ratings
  const entries = [];
  Object.entries(window.OTT_DATA).forEach(([num, platforms]) => {
    if (!platforms.includes('Crunchyroll')) return;
    const meta = window.RATING_DATA[num];
    if (!meta || meta.rating === null) return;
    const title = numToTitle[num] || `#${num}`;
    entries.push({ num: parseInt(num), title, rating: meta.rating });
  });

  entries.sort((a, b) => b.rating - a.rating);
  const top = entries.slice(0, 10);
  if (top.length === 0) { ctx.fillStyle = '#b0d4f0'; ctx.font = '14px Exo 2'; ctx.textAlign = 'center'; ctx.fillText('No data', W/2, H/2); return; }

  const maxRating = 10;
  const chartH = H - pad.top - pad.bottom;
  const chartW = W - pad.left - pad.right;
  const barH = Math.min(28, (chartH - (top.length - 1) * 6) / top.length);
  const colors = ['#FF6B6B','#FF8E53','#FFA07A','#FFD700','#98D8C8','#4ECDC4','#45B7D1','#85C1E9','#BB8FCE','#D2B4DE'];

  function drawBars(progress) {
    ctx.clearRect(0, 0, W, H);

    // Grid lines
    ctx.strokeStyle = 'rgba(0,229,255,0.07)';
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
      const x = pad.left + (chartW * i / 4);
      ctx.beginPath(); ctx.moveTo(x, pad.top); ctx.lineTo(x, H - pad.bottom); ctx.stroke();
      ctx.fillStyle = 'rgba(176,212,240,0.3)';
      ctx.font = '9px Exo 2';
      ctx.textAlign = 'center';
      ctx.fillText((maxRating * i / 4).toFixed(1), x, H - pad.bottom + 14);
    }

    // Bars
    top.forEach((item, i) => {
      const y = pad.top + i * (barH + 6);
      const barW = (item.rating / 100) * chartW * progress;
      ctx.fillStyle = colors[i];
      ctx.shadowColor = 'rgba(255,215,0,0.1)';
      ctx.shadowBlur = 6;
      const r = 4;
      if (barW > 0) {
        ctx.beginPath();
        ctx.moveTo(pad.left, y + r);
        ctx.lineTo(pad.left + barW - r, y);
        ctx.quadraticCurveTo(pad.left + barW, y, pad.left + barW, y + r);
        ctx.lineTo(pad.left + barW, y + barH - r);
        ctx.quadraticCurveTo(pad.left + barW, y + barH, pad.left + barW - r, y + barH);
        ctx.lineTo(pad.left + r, y + barH);
        ctx.quadraticCurveTo(pad.left, y + barH, pad.left, y + barH - r);
        ctx.closePath();
        ctx.fill();
      }
      ctx.shadowBlur = 0;

      // Title
      ctx.fillStyle = '#b0d4f0';
      ctx.font = '11px Exo 2';
      ctx.textAlign = 'right';
      let label = item.title;
      const maxW = pad.left - 18;
      if (ctx.measureText(label).width > maxW) {
        while (ctx.measureText(label + '...').width > maxW && label.length > 0) label = label.slice(0, -1);
        label += '...';
      }
      ctx.fillText(label, pad.left - 14, y + barH / 2 + 4);

      // Rating label fades in after bar reaches ~80%
      if (progress > 0.8) {
        ctx.globalAlpha = Math.min(1, (progress - 0.8) / 0.2);
        ctx.fillStyle = '#ffd700';
        ctx.font = 'bold 12px Exo 2';
        ctx.textAlign = 'left';
        ctx.fillText((item.rating / 10).toFixed(1) + '/10', pad.left + barW + 8, y + barH / 2 + 4);
        ctx.globalAlpha = 1;
      }
    });
  }

  const barDuration = 800;
  const barStart = performance.now();
  (function anim(now) {
    const t = Math.min((now - barStart) / barDuration, 1);
    drawBars(1 - Math.pow(1 - t, 3));
    if (t < 1) requestAnimationFrame(anim);
  })(performance.now());
}

const cards = document.querySelectorAll(".card");

function updateBadgeNumbers() {
  let count = 0;
  document.querySelectorAll('.card').forEach(card => {
    const badge = card.querySelector('.badge');
    if (!badge) return;
    const isVisible = card.style.display !== 'none' && !card.classList.contains('hidden');
    if (isVisible) {
      count++;
      badge.textContent = `#${count}`;
    }
  });
}

function showCardsOnScroll() {
  const triggerBottom = window.innerHeight * 0.85;
  cards.forEach(card => {
    const cardTop = card.getBoundingClientRect().top;
    if(cardTop < triggerBottom) {
      card.classList.add("show");
    }
  });
}

