// Chat memory cleanup flag to prevent memory leaks
// Clear old messages from DOM when threshold exceeded

const apiUrl = 'https://api.groq.com/openai/v1/chat/completions';

const GROQ_API_KEYS = [
  'GROQ_KEY_1',
  'GROQ_KEY_2',
  'GROQ_KEY_3'
];
let currentKeyIndex = 0;

function getNextKeyIndex() {
  currentKeyIndex = (currentKeyIndex + 1) % GROQ_API_KEYS.length;
  return currentKeyIndex;
}

async function fetchWithFallback(body) {
  let lastError = null;
  const startIndex = currentKeyIndex;
  let attempts = 0;

  do {
    const key = GROQ_API_KEYS[currentKeyIndex];
    try {
      const res = await fetch(apiUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer ' + key
        },
        body: JSON.stringify(body)
      });
      if (res.ok) return res;
      if (res.status === 429 || res.status === 401 || res.status >= 500) {
        lastError = new Error('Groq API error: ' + res.status);
        getNextKeyIndex();
        attempts++;
        continue;
      }
      return res;
    } catch (err) {
      lastError = err;
      getNextKeyIndex();
      attempts++;
    }
  } while (attempts < GROQ_API_KEYS.length);

  throw lastError || new Error('All Groq API keys exhausted');
}

