const chatBubble = document.getElementById('chatBubble');
const chatBox = document.getElementById('chatBox');
const chatMessages = document.getElementById('chatMessages');
const chatInput = document.getElementById('chatInput');

let chatHistory = [
  { role: "system", content: getSystemPrompt() }
];

// ===== LOCALSTORAGE FUNCTIONS - NEW =====
function saveChatToStorage() {
const toSave = chatHistory.filter(msg =>
  msg.role === 'user' || msg.role === 'assistant'
);  const trimmed = toSave.slice(-MAX_STORED_MSG);
  localStorage.setItem(CHAT_STORAGE_KEY, JSON.stringify(trimmed));
}

function restoreChatFromStorage() {
  const saved = localStorage.getItem(CHAT_STORAGE_KEY);
  if (!saved) return;

  try {
    const savedMessages = JSON.parse(saved);
    savedMessages.forEach(msg => {
      if (msg.role === 'user') {
        addMessage(msg.content, 'user', false); // false = don't save again
        chatHistory.push(msg);
      } else if (msg.role === 'assistant') {
        addMessage(msg.content, 'bot', false);
        chatHistory.push(msg);
      }
    });
  } catch (e) {
    console.error('Chat restore failed:', e);
    localStorage.removeItem(CHAT_STORAGE_KEY);
  }
}

// Call restore on page load
document.addEventListener('DOMContentLoaded', () => {
  restoreChatFromStorage();
});

// ===== TOGGLE CHAT =====
function toggleChat() {
  chatBox.classList.toggle('open');
  if (chatBox.classList.contains('open')) {
    chatInput.focus();
    if (typeof closeMenu === 'function') closeMenu();
  }
}

let isResponding = false;

// ===== SEND MESSAGE =====
async function sendMessage() {
  if (isResponding) return;
  const message = chatInput.value.trim();
  if (!message) return;

  isResponding = true;
  chatInput.disabled = true;

  let typingDiv = null;

  try {
    addMessage(message, 'user');
    chatInput.value = '';

    chatHistory.push({ role: 'user', content: message });

    if (chatHistory.length > 9) {
      chatHistory = [chatHistory[0],...chatHistory.slice(-8)];
    }

    typingDiv = addMessage('Typing...', 'bot typing');
    let messagesToSend = [...chatHistory];

    const response = await fetchWithFallback({
      model: 'llama-3.1-8b-instant',
      messages: messagesToSend,
      temperature: 0.8,
      max_tokens: 400,
      stream: false
    });

    const data = await response.json();

    if (data.choices && data.choices[0]) {
      if (typingDiv) typingDiv.remove();

      const botReply = data.choices[0].message.content;

      chatHistory.push({
        role: 'assistant',
        content: botReply
      });

      addMessage(botReply, 'bot');

      saveChatToStorage();
    } else {
      throw new Error('No response from API');
    }
  } catch (error) {
    if (typingDiv) typingDiv.remove();
    const msg = (error.message || '').includes('401') || (error.message || '').includes('429')
      ? 'The AI service is currently unavailable. Please try again later! ✨'
      : 'I worked Too Much Today, Try Again After a While! Till then, Enjoy many features from SideBar! ✨';
    addMessage(msg, 'bot');
    console.error('Chat Error:', error);
  }

  isResponding = false;
  chatInput.disabled = false;
  chatInput.focus();
}

// ===== ADD MESSAGE TO UI - PREMIUM ANIMATION VERSION =====
function addMessage(text, type, shouldSave = true) {
  const msgDiv = document.createElement('div');
  msgDiv.className = `msg ${type}`;

  // USER MESSAGE → instant
  if (type === 'user') {
    msgDiv.textContent = text;
  }

  // BOT MESSAGE → animated typing effect
  else if (type === 'bot') {

    // Create span for animated text
    const textSpan = document.createElement('span');
    msgDiv.appendChild(textSpan);

    let index = 0;

    // Typewriter effect
    function typeWriter() {
      if (index < text.length) {
        textSpan.textContent += text.charAt(index);
        index++;

        // Auto scroll while typing
        chatMessages.scrollTop = chatMessages.scrollHeight;

        setTimeout(typeWriter, 1); // typing speed
      }
    }

    // Small delay before bot starts typing
    setTimeout(() => {
      typeWriter();
    }, 250);
  }

  // TYPING INDICATOR
  else if (type.includes('typing')) {
    msgDiv.innerHTML = `
      <div class="typing-animation">
        <span></span>
        <span></span>
        <span></span>
      </div>
    `;
  }

  msgDiv.dataset.role = type === 'user' ? 'user' : 'assistant';

  // Smooth appearance
  msgDiv.style.opacity = '0';
  msgDiv.style.transform = 'translateY(10px)';

  chatMessages.appendChild(msgDiv);

  setTimeout(() => {
    msgDiv.style.transition = 'all 0.3s ease';
    msgDiv.style.opacity = '1';
    msgDiv.style.transform = 'translateY(0)';
  }, 10);

  chatMessages.scrollTop = chatMessages.scrollHeight;

  // Save
  if (shouldSave && (type === 'user' || type === 'bot')) {
    saveChatToStorage();
  }

  return msgDiv;
}


